PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?dob
WHERE {
  ?player wdt:P509 ?placeOfBirth;
          wdt:P2240 wd:Q2117549;
          wdt:P2937 2016;
          wdt:P2295 10;
          wdt:P413 wd:Q2523210;
          wdt:P569 ?dob.
}
LIMIT 10

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>

SELECT ?dob
WHERE {
  ?player wdt:P413 wd:Q2523210 ;
          p:P2295 ?draft .
  ?draft ps:P2295 10 ;
         pq:P2240 wd:Q2117549 ;
         pq:P585 ?draftDate .
  ?player wdt:P569 ?dob .
  FILTER(YEAR(?draftDate) = 2016)
}
LIMIT 1

